import{_ as t,o as a,c as i,a0 as s}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Email Settings","description":"","frontmatter":{},"headers":[],"relativePath":"admin/email-settings.md","filePath":"admin/email-settings.md"}'),o={name:"admin/email-settings.md"};function n(r,e,l,c,h,p){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="email-settings" tabindex="-1">Email Settings <a class="header-anchor" href="#email-settings" aria-label="Permalink to &quot;Email Settings&quot;">​</a></h1><p>This guide is mainly for <code>Supreme Admin</code> users. Some setups may also let a <code>King</code> open the page.</p><p>The Email Settings page controls whether the app uses <strong>Mock Email</strong> or <strong>SMTP Email</strong>, and lets you send a test message.</p><blockquote><p>Screenshot placeholder: <code>admin-email.png</code> (S77)</p></blockquote><h2 id="what-you-can-configure" tabindex="-1">What you can configure <a class="header-anchor" href="#what-you-can-configure" aria-label="Permalink to &quot;What you can configure&quot;">​</a></h2><p>The page includes:</p><ul><li>provider choice: <strong>Mock Email</strong> or <strong>SMTP Email</strong></li><li>SMTP host</li><li>SMTP port</li><li>SMTP username</li><li>SMTP password</li><li>secure-connection toggle</li><li>from email</li><li>from name</li><li>test recipient email</li><li>support contact</li></ul><p>The current password is not shown back to you. If a password already exists, the form lets you leave it blank to keep the current one.</p><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>Use <strong>Send test email</strong> after saving to confirm the current setup can send mail the way you expect.</p><h2 id="which-system-emails-are-sent" tabindex="-1">Which system emails are sent <a class="header-anchor" href="#which-system-emails-are-sent" aria-label="Permalink to &quot;Which system emails are sent&quot;">​</a></h2><p>The exact list of app events that send email is still something you should <strong>verify in the app or check with your admin</strong> rather than relying on a fixed checklist here.</p><p>That is the cautious approach for this documentation because the planning notes still flag the full trigger list as unverified.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>use Mock Email in development or test setups</li><li>switch to SMTP for real delivery</li><li>send a test after any SMTP change</li><li>keep the support contact current so users know who to reach</li></ul>',15)])])}const u=t(o,[["render",n]]);export{d as __pageData,u as default};
